import{_ as n,o as s,c as t,a4 as e}from"./chunks/framework._in6GHBg.js";const g=JSON.parse('{"title":"数列详解","description":"","frontmatter":{},"headers":[],"relativePath":"math/Math-Learn-Detail-006-数列详解-V1.0-20260405.md","filePath":"math/Math-Learn-Detail-006-数列详解-V1.0-20260405.md"}'),l={name:"math/Math-Learn-Detail-006-数列详解-V1.0-20260405.md"};function p(i,a,o,r,d,c){return s(),t("div",null,[...a[0]||(a[0]=[e(`<h1 id="数列详解" tabindex="-1">数列详解 <a class="header-anchor" href="#数列详解" aria-label="Permalink to &quot;数列详解&quot;">​</a></h1><p><strong>从&quot;一列数&quot;到&quot;离散变化的数学模型&quot;</strong></p><hr><h2 id="一、本章地图" tabindex="-1">一、本章地图 <a class="header-anchor" href="#一、本章地图" aria-label="Permalink to &quot;一、本章地图&quot;">​</a></h2><h3 id="核心目标" tabindex="-1">核心目标 <a class="header-anchor" href="#核心目标" aria-label="Permalink to &quot;核心目标&quot;">​</a></h3><p>学完本章，你将：</p><ol><li>理解数列是定义在正整数集上的函数（离散函数）</li><li>掌握等差数列和等比数列的通项与求和公式</li><li>能处理递推数列和数列综合问题</li></ol><h3 id="知识网络" tabindex="-1">知识网络 <a class="header-anchor" href="#知识网络" aria-label="Permalink to &quot;知识网络&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>数列</span></span>
<span class="line"><span>├── 数列基础</span></span>
<span class="line"><span>│   ├── 数列概念（离散函数）</span></span>
<span class="line"><span>│   ├── 通项公式aₙ</span></span>
<span class="line"><span>│   └── 前n项和Sₙ</span></span>
<span class="line"><span>├── 等差数列 ⭐</span></span>
<span class="line"><span>│   ├── 定义与通项公式</span></span>
<span class="line"><span>│   ├── 等差数列性质</span></span>
<span class="line"><span>│   └── 前n项和公式</span></span>
<span class="line"><span>├── 等比数列 ⭐</span></span>
<span class="line"><span>│   ├── 定义与通项公式</span></span>
<span class="line"><span>│   ├── 等比数列性质</span></span>
<span class="line"><span>│   └── 前n项和公式</span></span>
<span class="line"><span>└── 数列综合</span></span>
<span class="line"><span>    ├── 递推数列求通项 ⭐</span></span>
<span class="line"><span>    ├── 数列求和方法 ⭐</span></span>
<span class="line"><span>    └── 数列与不等式综合</span></span></code></pre></div><h3 id="前后联系" tabindex="-1">前后联系 <a class="header-anchor" href="#前后联系" aria-label="Permalink to &quot;前后联系&quot;">​</a></h3><ul><li><strong>前置知识</strong>：函数概念、指数对数运算</li><li><strong>后续应用</strong>：导数（微积分中数列极限）、数学归纳法</li><li><strong>跨学科联系</strong>：金融（复利计算）、生物（种群增长）、计算机（算法复杂度）</li></ul><hr><h2 id="二、概念定义" tabindex="-1">二、概念定义 <a class="header-anchor" href="#二、概念定义" aria-label="Permalink to &quot;二、概念定义&quot;">​</a></h2><h3 id="_2-1-数列的基本概念" tabindex="-1">2.1 数列的基本概念 <a class="header-anchor" href="#_2-1-数列的基本概念" aria-label="Permalink to &quot;2.1 数列的基本概念&quot;">​</a></h3><p><strong>定义</strong>：按一定顺序排列的一列数a₁, a₂, a₃, ..., aₙ, ...</p><p><strong>理解</strong>：</p><ul><li>数列是<strong>定义域为正整数集</strong>的函数</li><li>aₙ = f(n)，n=1,2,3,...</li><li>与函数的区别：数列是<strong>离散的</strong>，函数通常是连续的</li></ul><p><strong>通项公式</strong>：aₙ与n的关系式，如aₙ = 2n-1</p><p><strong>前n项和</strong>：Sₙ = a₁ + a₂ + ... + aₙ</p><p><strong>重要关系</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>aₙ = S₁ (n=1)</span></span>
<span class="line"><span>aₙ = Sₙ - Sₙ₋₁ (n≥2)</span></span></code></pre></div><hr><h3 id="_2-2-等差数列-⭐" tabindex="-1">2.2 等差数列 ⭐ <a class="header-anchor" href="#_2-2-等差数列-⭐" aria-label="Permalink to &quot;2.2 等差数列 ⭐&quot;">​</a></h3><p><strong>定义</strong>：从第二项起，每一项与前一项的差为常数d（公差）</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>aₙ₊₁ - aₙ = d</span></span></code></pre></div><p><strong>通项公式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>aₙ = a₁ + (n-1)d</span></span></code></pre></div><p><strong>变形</strong>：</p><ul><li>aₙ = aₘ + (n-m)d（任两项关系）</li><li>d = (aₙ-aₘ)/(n-m)</li></ul><p><strong>等差数列的性质</strong>：</p><ol><li><strong>等差中项</strong>：2b = a + c（a, b, c成等差）</li><li><strong>下标和性质</strong>：若m+n=p+q，则aₘ+aₙ=aₚ+a_q</li></ol><p><strong>前n项和公式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Sₙ = n(a₁+aₙ)/2 = na₁ + n(n-1)d/2</span></span></code></pre></div><p><strong>求和公式特点</strong>：</p><ul><li>Sₙ是关于n的二次函数（无常数项）</li><li>Sₙ = An² + Bn，其中A=d/2, B=a₁-d/2</li></ul><hr><h3 id="_2-3-等比数列-⭐" tabindex="-1">2.3 等比数列 ⭐ <a class="header-anchor" href="#_2-3-等比数列-⭐" aria-label="Permalink to &quot;2.3 等比数列 ⭐&quot;">​</a></h3><p><strong>定义</strong>：从第二项起，每一项与前一项的比为常数q（公比，q≠0）</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>aₙ₊₁ / aₙ = q</span></span></code></pre></div><p><strong>通项公式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>aₙ = a₁ · q^(n-1)</span></span></code></pre></div><p><strong>等比数列的性质</strong>：</p><ol><li><strong>等比中项</strong>：b² = ac（a, b, c成等比，ac&gt;0）</li><li><strong>下标和性质</strong>：若m+n=p+q，则aₘ·aₙ=aₚ·a_q</li></ol><p><strong>前n项和公式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Sₙ = na₁ (q=1)</span></span>
<span class="line"><span>Sₙ = a₁(1-qⁿ)/(1-q) = a₁(qⁿ-1)/(q-1) (q≠1)</span></span></code></pre></div><p><strong>注意</strong>：</p><ul><li>等比数列各项和公比都不能为0</li><li>求和时先判断q是否为1</li></ul><hr><h3 id="_2-4-递推数列求通项-⭐" tabindex="-1">2.4 递推数列求通项 ⭐ <a class="header-anchor" href="#_2-4-递推数列求通项-⭐" aria-label="Permalink to &quot;2.4 递推数列求通项 ⭐&quot;">​</a></h3><p><strong>类型1：aₙ₊₁ = aₙ + f(n)</strong>（累加法）</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>aₙ = a₁ + Σ(k=1 to n-1) f(k)</span></span></code></pre></div><p><strong>类型2：aₙ₊₁ = aₙ · f(n)</strong>（累乘法）</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>aₙ = a₁ · Π(k=1 to n-1) f(k)</span></span></code></pre></div><p><strong>类型3：aₙ₊₁ = paₙ + q</strong>（构造等比）</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>设aₙ₊₁ + λ = p(aₙ + λ)，解出λ</span></span>
<span class="line"><span>则{aₙ+λ}是等比数列</span></span></code></pre></div><p><strong>类型4：aₙ₊₁ = paₙ + f(n)</strong>（两边同除p^(n+1)）</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>aₙ₊₁/p^(n+1) = aₙ/pⁿ + f(n)/p^(n+1)</span></span>
<span class="line"><span>令bₙ = aₙ/pⁿ，转化为类型1</span></span></code></pre></div><hr><h3 id="_2-5-数列求和方法-⭐" tabindex="-1">2.5 数列求和方法 ⭐ <a class="header-anchor" href="#_2-5-数列求和方法-⭐" aria-label="Permalink to &quot;2.5 数列求和方法 ⭐&quot;">​</a></h3><p><strong>公式法</strong>：</p><ul><li>等差数列：用Sₙ公式</li><li>等比数列：用Sₙ公式</li></ul><p><strong>分组求和</strong>：</p><ul><li>把数列分成几组，分别求和再相加</li><li>适用于：aₙ = bₙ + cₙ，其中{bₙ}、{cₙ}可求和</li></ul><p><strong>裂项相消法</strong>：</p><ul><li>把aₙ拆成bₙ - bₙ₊₁的形式</li><li>求和时中间项抵消</li></ul><p><strong>常见裂项</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1/[n(n+1)] = 1/n - 1/(n+1)</span></span>
<span class="line"><span>1/[(2n-1)(2n+1)] = (1/2)[1/(2n-1) - 1/(2n+1)]</span></span></code></pre></div><p><strong>错位相减法</strong>：</p><ul><li>适用于：等差×等比型数列</li><li>Sₙ = a₁b₁ + a₂b₂ + ... + aₙbₙ，其中{aₙ}等差，{bₙ}等比</li></ul><p><strong>步骤</strong>：</p><ol><li>写出Sₙ</li><li>两边同乘公比q，得qSₙ</li><li>两式相减（错位相减）</li><li>整理求Sₙ</li></ol><hr><h2 id="三、典型例题" tabindex="-1">三、典型例题 <a class="header-anchor" href="#三、典型例题" aria-label="Permalink to &quot;三、典型例题&quot;">​</a></h2><h3 id="例题1-等差数列基本量计算" tabindex="-1">例题1：等差数列基本量计算 <a class="header-anchor" href="#例题1-等差数列基本量计算" aria-label="Permalink to &quot;例题1：等差数列基本量计算&quot;">​</a></h3><p><strong>题目</strong>：等差数列{aₙ}中，a₃=5，a₇=13，求a₁₀和S₁₀。</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>法1：用基本量</span></span>
<span class="line"><span>a₃ = a₁+2d = 5</span></span>
<span class="line"><span>a₇ = a₁+6d = 13</span></span>
<span class="line"><span>相减：4d = 8 → d=2</span></span>
<span class="line"><span>代入：a₁=1</span></span>
<span class="line"><span></span></span>
<span class="line"><span>a₁₀ = a₁+9d = 1+18 = 19</span></span>
<span class="line"><span>S₁₀ = 10(a₁+a₁₀)/2 = 5×20 = 100</span></span>
<span class="line"><span></span></span>
<span class="line"><span>法2：用性质</span></span>
<span class="line"><span>a₇ = a₃+4d → 13=5+4d → d=2</span></span>
<span class="line"><span>a₁₀ = a₇+3d = 13+6 = 19</span></span></code></pre></div><hr><h3 id="例题2-等比数列基本量计算" tabindex="-1">例题2：等比数列基本量计算 <a class="header-anchor" href="#例题2-等比数列基本量计算" aria-label="Permalink to &quot;例题2：等比数列基本量计算&quot;">​</a></h3><p><strong>题目</strong>：等比数列{aₙ}中，a₂=6，a₅=48，求a₁和S₅。</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>a₂ = a₁q = 6</span></span>
<span class="line"><span>a₅ = a₁q⁴ = 48</span></span>
<span class="line"><span>相除：q³ = 8 → q=2</span></span>
<span class="line"><span>代入：a₁=3</span></span>
<span class="line"><span></span></span>
<span class="line"><span>S₅ = 3(1-2⁵)/(1-2) = 3(1-32)/(-1) = 93</span></span></code></pre></div><hr><h3 id="例题3-递推数列求通项" tabindex="-1">例题3：递推数列求通项 <a class="header-anchor" href="#例题3-递推数列求通项" aria-label="Permalink to &quot;例题3：递推数列求通项&quot;">​</a></h3><p><strong>题目</strong>：数列{aₙ}满足a₁=1，aₙ₊₁=2aₙ+1，求aₙ。</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>构造：aₙ₊₁+1 = 2aₙ+1+1 = 2(aₙ+1)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>设bₙ = aₙ+1，则bₙ₊₁ = 2bₙ，b₁=2</span></span>
<span class="line"><span>∴ {bₙ}是等比数列，公比q=2</span></span>
<span class="line"><span></span></span>
<span class="line"><span>bₙ = 2·2^(n-1) = 2ⁿ</span></span>
<span class="line"><span>∴ aₙ = 2ⁿ - 1</span></span></code></pre></div><p><strong>验证</strong>：</p><ul><li>n=1：a₁=2-1=1 ✓</li><li>n=2：a₂=4-1=3，而2a₁+1=3 ✓</li></ul><hr><h3 id="例题4-裂项相消求和" tabindex="-1">例题4：裂项相消求和 <a class="header-anchor" href="#例题4-裂项相消求和" aria-label="Permalink to &quot;例题4：裂项相消求和&quot;">​</a></h3><p><strong>题目</strong>：求Sₙ = 1/(1×2) + 1/(2×3) + ... + 1/[n(n+1)]</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1/[k(k+1)] = 1/k - 1/(k+1)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Sₙ = (1-1/2) + (1/2-1/3) + ... + (1/n-1/(n+1))</span></span>
<span class="line"><span>   = 1 - 1/(n+1)  【中间项全部抵消】</span></span>
<span class="line"><span>   = n/(n+1)</span></span></code></pre></div><hr><h3 id="例题5-错位相减求和" tabindex="-1">例题5：错位相减求和 <a class="header-anchor" href="#例题5-错位相减求和" aria-label="Permalink to &quot;例题5：错位相减求和&quot;">​</a></h3><p><strong>题目</strong>：求Sₙ = 1×2 + 2×2² + 3×2³ + ... + n×2ⁿ</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Sₙ = 1×2 + 2×2² + 3×2³ + ... + n×2ⁿ  ...①</span></span>
<span class="line"><span>2Sₙ =     1×2² + 2×2³ + ... + (n-1)×2ⁿ + n×2^(n+1)  ...②</span></span>
<span class="line"><span></span></span>
<span class="line"><span>①-②：</span></span>
<span class="line"><span>-Sₙ = 2 + 2² + 2³ + ... + 2ⁿ - n×2^(n+1)</span></span>
<span class="line"><span>    = 2(2ⁿ-1)/(2-1) - n×2^(n+1)</span></span>
<span class="line"><span>    = 2^(n+1) - 2 - n×2^(n+1)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>∴ Sₙ = (n-1)×2^(n+1) + 2</span></span></code></pre></div><hr><h2 id="四、配套练习" tabindex="-1">四、配套练习 <a class="header-anchor" href="#四、配套练习" aria-label="Permalink to &quot;四、配套练习&quot;">​</a></h2><h3 id="基础练习-必做" tabindex="-1">基础练习（必做） <a class="header-anchor" href="#基础练习-必做" aria-label="Permalink to &quot;基础练习（必做）&quot;">​</a></h3><p><strong>练习1</strong>：等差数列{aₙ}中，a₁=3，d=2，求a₁₀和S₁₀。</p><p><strong>练习2</strong>：等比数列{aₙ}中，a₁=2，q=3，求a₅和S₅。</p><p><strong>练习3</strong>：数列{aₙ}满足a₁=1，aₙ₊₁=aₙ+2n，求aₙ。</p><p><strong>练习4</strong>：求Sₙ = 1 + 3 + 5 + ... + (2n-1)。</p><p><strong>参考答案</strong>：</p><ul><li>练习1：a₁₀=21，S₁₀=120</li><li>练习2：a₅=162，S₅=242</li><li>练习3：aₙ=n²-n+1（用累加法）</li><li>练习4：Sₙ=n²（等差数列求和或n²）</li></ul><hr><h3 id="提高练习-选做" tabindex="-1">提高练习（选做） <a class="header-anchor" href="#提高练习-选做" aria-label="Permalink to &quot;提高练习（选做）&quot;">​</a></h3><p><strong>练习5</strong>：数列{aₙ}满足a₁=1，aₙ₊₁=3aₙ+2，求aₙ。</p><p><strong>练习6</strong>：求Sₙ = 1/2 + 2/2² + 3/2³ + ... + n/2ⁿ。</p><hr><h2 id="五、faq常见问题" tabindex="-1">五、FAQ常见问题 <a class="header-anchor" href="#五、faq常见问题" aria-label="Permalink to &quot;五、FAQ常见问题&quot;">​</a></h2><h3 id="faq-1-等差等比公式总记混" tabindex="-1">FAQ 1：等差等比公式总记混 <a class="header-anchor" href="#faq-1-等差等比公式总记混" aria-label="Permalink to &quot;FAQ 1：等差等比公式总记混&quot;">​</a></h3><p><strong>对比记忆</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:center;"></th><th style="text-align:center;">等差</th><th style="text-align:center;">等比</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>定义</strong></td><td style="text-align:center;">差相等</td><td style="text-align:center;">比相等</td></tr><tr><td style="text-align:center;"><strong>通项</strong></td><td style="text-align:center;">aₙ=a₁+(n-1)d</td><td style="text-align:center;">aₙ=a₁·q^(n-1)</td></tr><tr><td style="text-align:center;"><strong>中项</strong></td><td style="text-align:center;">2b=a+c</td><td style="text-align:center;">b²=ac</td></tr><tr><td style="text-align:center;"><strong>求和</strong></td><td style="text-align:center;">n(a₁+aₙ)/2</td><td style="text-align:center;">a₁(1-qⁿ)/(1-q)</td></tr></tbody></table><p><strong>口诀</strong>：</p><ul><li>等差：加公差</li><li>等比：乘公比</li></ul><hr><h3 id="faq-2-由sn求an时总忘n-1的情况" tabindex="-1">FAQ 2：由Sₙ求aₙ时总忘n=1的情况 <a class="header-anchor" href="#faq-2-由sn求an时总忘n-1的情况" aria-label="Permalink to &quot;FAQ 2：由Sₙ求aₙ时总忘n=1的情况&quot;">​</a></h3><p><strong>正确写法</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>aₙ = S₁ (n=1时)</span></span>
<span class="line"><span>aₙ = Sₙ - Sₙ₋₁ (n≥2时)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>最后要检验n=1时，Sₙ-Sₙ₋₁是否等于S₁</span></span>
<span class="line"><span>若不等，要写成分段形式</span></span></code></pre></div><p><strong>示例</strong>：</p><ul><li>若Sₙ=n²，则a₁=1，n≥2时aₙ=n²-(n-1)²=2n-1</li><li>检验：n=1时，2×1-1=1=a₁，统一写aₙ=2n-1</li></ul><hr><h3 id="faq-3-递推数列不知道怎么构造" tabindex="-1">FAQ 3：递推数列不知道怎么构造 <a class="header-anchor" href="#faq-3-递推数列不知道怎么构造" aria-label="Permalink to &quot;FAQ 3：递推数列不知道怎么构造&quot;">​</a></h3><p><strong>常见类型对照</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:center;">递推式</th><th style="text-align:center;">构造方法</th><th style="text-align:center;">新数列</th></tr></thead><tbody><tr><td style="text-align:center;">aₙ₊₁=aₙ+f(n)</td><td style="text-align:center;">累加</td><td style="text-align:center;">-</td></tr><tr><td style="text-align:center;">aₙ₊₁=aₙ·f(n)</td><td style="text-align:center;">累乘</td><td style="text-align:center;">-</td></tr><tr><td style="text-align:center;">aₙ₊₁=paₙ+q</td><td style="text-align:center;">设aₙ₊₁+λ=p(aₙ+λ)</td><td style="text-align:center;">{aₙ+λ}等比</td></tr><tr><td style="text-align:center;">aₙ₊₁=paₙ+qⁿ</td><td style="text-align:center;">两边同除q^(n+1)或p^(n+1)</td><td style="text-align:center;">转化为累加型</td></tr></tbody></table><hr><h3 id="faq-4-错位相减时总是算错" tabindex="-1">FAQ 4：错位相减时总是算错 <a class="header-anchor" href="#faq-4-错位相减时总是算错" aria-label="Permalink to &quot;FAQ 4：错位相减时总是算错&quot;">​</a></h3><p><strong>检查点</strong>：</p><ol><li>对齐次数：Sₙ和qSₙ要错位一位</li><li>相减方向：Sₙ - qSₙ还是qSₙ - Sₙ，注意符号</li><li>等比数列项数：相减后的等比数列有多少项</li><li>最后整理：别忘了除以(1-q)</li></ol><p><strong>建议</strong>：</p><ul><li>先写几项找规律</li><li>用n=1,2验证结果</li></ul><hr><h2 id="六、本章检查清单" tabindex="-1">六、本章检查清单 <a class="header-anchor" href="#六、本章检查清单" aria-label="Permalink to &quot;六、本章检查清单&quot;">​</a></h2><ul><li>[ ] 理解数列是离散函数的概念</li><li>[ ] 熟练运用等差数列的通项和求和公式</li><li>[ ] 熟练运用等比数列的通项和求和公式</li><li>[ ] 掌握由Sₙ求aₙ的方法（注意n=1）</li><li>[ ] 会处理常见类型的递推数列</li><li>[ ] 掌握裂项相消法的常见裂项形式</li><li>[ ] 掌握错位相减法的步骤</li></ul><hr><p><strong>文档编号</strong>: Math-Learn-Detail-006<br><strong>版本</strong>: V1.0<br><strong>日期</strong>: 20260405</p>`,140)])])}const u=n(l,[["render",p]]);export{g as __pageData,u as default};
